def merge_sort(arr):
    """Sort an array using the merge sort algorithm."""
    if len(arr) <= 1:
        return arr

    mid = len(arr) // 2
    left = merge_sort(arr[:mid])
    right = merge_sort(arr[mid:])

    return merge(left, right)

def merge(left, right):
    """Merge two sorted arrays into one sorted array."""
    result = []
    i = j = 0

    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i])
            i += 1
        else:
            result.append(right[j])
            j += 1

    result.extend(left[i:])
    result.extend(right[j:])
    return result

from dataclasses import dataclass, field
from typing import Optional, List
import heapq

@dataclass(order=True)
class Task:
    priority: int
    name: str = field(compare=False)
    description: str = field(compare=False, default='')
    completed: bool = field(compare=False, default=False)

class PriorityTaskQueue:
    """A priority queue for managing tasks."""

    def __init__(self):
        self._heap: List[Task] = []
        self._counter = 0

    def add_task(self, name: str, priority: int = 0, description: str = '') -> Task:
        task = Task(priority=priority, name=name, description=description)
        heapq.heappush(self._heap, task)
        self._counter += 1
        return task

    def get_next(self) -> Optional[Task]:
        while self._heap:
            task = heapq.heappop(self._heap)
            if not task.completed:
                return task
        return None

    def peek(self) -> Optional[Task]:
        for task in self._heap:
            if not task.completed:
                return task
        return None

    @property
    def pending_count(self) -> int:
        return sum(1 for t in self._heap if not t.completed)

    def __len__(self) -> int:
        return self.pending_count

class EventEmitter {
  constructor() {
    this.events = new Map();
  }

  on(event, listener) {
    if (!this.events.has(event)) {
      this.events.set(event, []);
    }
    this.events.get(event).push({ listener, once: false });
    return this;
  }

  once(event, listener) {
    if (!this.events.has(event)) {
      this.events.set(event, []);
    }
    this.events.get(event).push({ listener, once: true });
    return this;
  }

  emit(event, ...args) {
    if (!this.events.has(event)) return false;
    const listeners = this.events.get(event);
    const remaining = [];
    for (const entry of listeners) {
      entry.listener.apply(this, args);
      if (!entry.once) remaining.push(entry);
    }
    this.events.set(event, remaining);
    return true;
  }

  off(event, listener) {
    if (!this.events.has(event)) return this;
    const filtered = this.events.get(event)
      .filter(entry => entry.listener !== listener);
    this.events.set(event, filtered);
    return this;
  }

  listenerCount(event) {
    return this.events.has(event) ? this.events.get(event).length : 0;
  }
}

import asyncio
from typing import Any, Callable, Dict, Optional
from functools import wraps
import time

class AsyncCache:
    """Async-compatible LRU cache with TTL support."""

    def __init__(self, maxsize: int = 128, ttl: Optional[float] = None):
        self._cache: Dict[str, dict] = {}
        self._maxsize = maxsize
        self._ttl = ttl
        self._lock = asyncio.Lock()

    def _make_key(self, args, kwargs) -> str:
        return str((args, tuple(sorted(kwargs.items()))))

    def _is_expired(self, entry: dict) -> bool:
        if self._ttl is None:
            return False
        return (time.monotonic() - entry['time']) > self._ttl

    async def get(self, key: str) -> Optional[Any]:
        async with self._lock:
            if key in self._cache and not self._is_expired(self._cache[key]):
                return self._cache[key]['value']
            elif key in self._cache:
                del self._cache[key]
            return None

    async def set(self, key: str, value: Any) -> None:
        async with self._lock:
            if len(self._cache) >= self._maxsize and key not in self._cache:
                oldest = min(self._cache, key=lambda k: self._cache[k]['time'])
                del self._cache[oldest]
            self._cache[key] = {'value': value, 'time': time.monotonic()}

    def cached(self, func: Callable) -> Callable:
        @wraps(func)
        async def wrapper(*args, **kwargs):
            key = self._make_key(args, kwargs)
            result = await self.get(key)
            if result is not None:
                return result
            result = await func(*args, **kwargs)
            await self.set(key, result)
            return result
        return wrapper

function debounce(fn, delay, { leading = false, trailing = true, maxWait } = {}) {
  let timerId = null;
  let lastCallTime = null;
  let lastInvokeTime = 0;
  let result;

  function invokeFunc(time) {
    lastInvokeTime = time;
    result = fn.apply(this, arguments);
    return result;
  }

  function shouldInvoke(time) {
    const timeSinceLastCall = time - (lastCallTime || 0);
    const timeSinceLastInvoke = time - lastInvokeTime;
    return (
      lastCallTime === null ||
      timeSinceLastCall >= delay ||
      (maxWait !== undefined && timeSinceLastInvoke >= maxWait)
    );
  }

  function startTimer(pendingFunc, wait) {
    timerId = setTimeout(pendingFunc, wait);
  }

  function cancelTimer() {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
  }

  function debounced(...args) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);
    lastCallTime = time;

    if (isInvoking && leading && timerId === null) {
      invokeFunc.apply(this, args);
    }

    cancelTimer();

    if (trailing) {
      startTimer(() => {
        if (trailing) invokeFunc.apply(this, args);
        timerId = null;
      }, delay);
    }
  }

  debounced.cancel = cancelTimer;
  debounced.flush = function () {
    cancelTimer();
    invokeFunc.apply(this, arguments);
  };

  return debounced;
}

from typing import TypeVar, Generic, Iterator, Optional

T = TypeVar('T')

class Node(Generic[T]):
    __slots__ = ('value', 'prev', 'next')

    def __init__(self, value: T):
        self.value = value
        self.prev: Optional['Node[T]'] = None
        self.next: Optional['Node[T]'] = None

class DoublyLinkedList(Generic[T]):
    def __init__(self):
        self._head: Optional[Node[T]] = None
        self._tail: Optional[Node[T]] = None
        self._size: int = 0

    def append(self, value: T) -> Node[T]:
        node = Node(value)
        if self._tail:
            self._tail.next = node
            node.prev = self._tail
            self._tail = node
        else:
            self._head = self._tail = node
        self._size += 1
        return node

    def prepend(self, value: T) -> Node[T]:
        node = Node(value)
        if self._head:
            self._head.prev = node
            node.next = self._head
            self._head = node
        else:
            self._head = self._tail = node
        self._size += 1
        return node

    def remove(self, node: Node[T]) -> T:
        if node.prev:
            node.prev.next = node.next
        else:
            self._head = node.next
        if node.next:
            node.next.prev = node.prev
        else:
            self._tail = node.prev
        self._size -= 1
        return node.value

    def __iter__(self) -> Iterator[T]:
        current = self._head
        while current:
            yield current.value
            current = current.next

    def __len__(self) -> int:
        return self._size

    def __reversed__(self) -> Iterator[T]:
        current = self._tail
        while current:
            yield current.value
            current = current.prev

import hashlib
import json
from time import time
from typing import List, Optional

class Block:
    def __init__(self, index: int, transactions: List[dict], previous_hash: str):
        self.index = index
        self.timestamp = time()
        self.transactions = transactions
        self.previous_hash = previous_hash
        self.nonce = 0
        self.hash = self.compute_hash()

    def compute_hash(self) -> str:
        block_data = json.dumps({
            'index': self.index,
            'timestamp': self.timestamp,
            'transactions': self.transactions,
            'previous_hash': self.previous_hash,
            'nonce': self.nonce
        }, sort_keys=True)
        return hashlib.sha256(block_data.encode()).hexdigest()

class Blockchain:
    difficulty = 2

    def __init__(self):
        self.chain: List[Block] = []
        self.pending_transactions: List[dict] = []
        self._create_genesis_block()

    def _create_genesis_block(self) -> None:
        genesis = Block(0, [], '0')
        self.chain.append(genesis)

    def add_transaction(self, sender: str, recipient: str, amount: float) -> int:
        self.pending_transactions.append({
            'sender': sender, 'recipient': recipient, 'amount': amount
        })
        return self.last_block.index + 1

    def mine_block(self) -> Block:
        block = Block(len(self.chain), self.pending_transactions, self.last_block.hash)
        while not block.hash.startswith('0' * self.difficulty):
            block.nonce += 1
            block.hash = block.compute_hash()
        self.chain.append(block)
        self.pending_transactions = []
        return block

    @property
    def last_block(self) -> Block:
        return self.chain[-1]

    def is_valid(self) -> bool:
        for i in range(1, len(self.chain)):
            current = self.chain[i]
            previous = self.chain[i-1]
            if current.hash != current.compute_hash():
                return False
            if current.previous_hash != previous.hash:
                return False
        return True

class Router {
  constructor() {
    this.routes = new Map();
    this.middleware = [];
    this.notFoundHandler = (req, res) => res.status(404).json({ error: 'Not Found' });
  }

  use(fn) {
    this.middleware.push(fn);
    return this;
  }

  route(method, path, ...handlers) {
    const key = `${method.toUpperCase()}:${path}`;
    const pattern = path.replace(/:([^/]+)/g, '(?<$1>[^/]+)');
    this.routes.set(key, {
      pattern: new RegExp(`^${pattern}$`),
      handlers: [...this.middleware, ...handlers],
      method: method.toUpperCase()
    });
    return this;
  }

  get(path, ...handlers) { return this.route('GET', path, ...handlers); }
  post(path, ...handlers) { return this.route('POST', path, ...handlers); }
  put(path, ...handlers) { return this.route('PUT', path, ...handlers); }
  delete(path, ...handlers) { return this.route('DELETE', path, ...handlers); }

  async handle(req) {
    for (const [key, route] of this.routes) {
      if (req.method !== route.method) continue;
      const match = req.url.match(route.pattern);
      if (match) {
        req.params = match.groups || {};
        const res = new Response();
        for (const handler of route.handlers) {
          await handler(req, res);
          if (res.sent) return res;
        }
        return res;
      }
    }
    const res = new Response();
    this.notFoundHandler(req, res);
    return res;
  }
}

