from typing import Callable, Dict, List, Optional, Tuple

class MarkdownParser:
    """Simple Markdown to HTML converter."""

    def __init__(self):
        self.inline_rules: List[Tuple[str, Callable]] = [
            (r'\*\*(.+?)\*\*', lambda m: f'<strong>{m.group(1)}</strong>'),
            (r'\*(.+?)\*', lambda m: f'<em>{m.group(1)}</em>'),
            (r'`(.+?)`', lambda m: f'<code>{m.group(1)}</code>'),
            (r'\[(.+?)\]\((.+?)\)', lambda m: f'<a href="{m.group(2)}">{m.group(1)}</a>'),
            (r'!\[(.+?)\]\((.+?)\)', lambda m: f'<img src="{m.group(2)}" alt="{m.group(1)}">')
        ]

    def parse(self, text: str) -> str:
        lines = text.split('\n')
        html_parts: List[str] = []
        i = 0
        while i < len(lines):
            line = lines[i]
            if line.startswith('#'):
                level = len(line) - len(line.lstrip('#'))
                level = min(level, 6)
                content = self._inline(line[level:].strip())
                html_parts.append(f'<h{level}>{content}</h{level}>')
            elif line.startswith('- ') or line.startswith('* '):
                items = []
                while i < len(lines) and (lines[i].startswith('- ') or lines[i].startswith('* ')):
                    items.append(f'<li>{self._inline(lines[i][2:])}</li>')
                    i += 1
                html_parts.append(f'<ul>{"\n".join(items)}</ul>')
                continue
            elif line.startswith('>'):
                content = self._inline(line[1:].strip())
                html_parts.append(f'<blockquote>{content}</blockquote>')
            elif line.strip() == '':
                pass
            else:
                content = self._inline(line)
                html_parts.append(f'<p>{content}</p>')
            i += 1
        return '\n'.join(html_parts)

    def _inline(self, text: str) -> str:
        for pattern, handler in self.inline_rules:
            text = re.sub(pattern, handler, text)
        return text

class VirtualDOM {
  static createElement(type, props = {}, ...children) {
    return {
      type,
      props: { ...props, children: children.flat().map(child =>
        typeof child === 'object' ? child : { type: 'TEXT', props: { nodeValue: child, children: [] } }
      )}
    };
  }

  static render(vnode, container) {
    const dom = vnode.type === 'TEXT'
      ? document.createTextNode(vnode.props.nodeValue)
      : document.createElement(vnode.type);

    Object.entries(vnode.props)
      .filter(([key]) => key !== 'children')
      .forEach(([key, value]) => {
        if (key.startsWith('on')) {
          dom.addEventListener(key.slice(2).toLowerCase(), value);
        } else {
          dom[key] = value;
        }
      });

    vnode.props.children.forEach(child => VirtualDOM.render(child, dom));
    container.appendChild(dom);
    return dom;
  }

  static diff(oldVNode, newVNode, parent, index = 0) {
    const existingNode = parent.childNodes[index];
    if (!newVNode) {
      if (existingNode) parent.removeChild(existingNode);
      return;
    }
    if (!oldVNode) {
      parent.appendChild(VirtualDOM.render(newVNode, parent));
      return;
    }
    if (oldVNode.type !== newVNode.type) {
      parent.replaceChild(VirtualDOM.render(newVNode, parent), existingNode);
      return;
    }
    if (newVNode.type === 'TEXT') {
      if (oldVNode.props.nodeValue !== newVNode.props.nodeValue) {
        existingNode.nodeValue = newVNode.props.nodeValue;
      }
      return;
    }
    const maxLen = Math.max(
      oldVNode.props.children.length,
      newVNode.props.children.length
    );
    for (let i = 0; i < maxLen; i++) {
      VirtualDOM.diff(oldVNode.props.children[i], newVNode.props.children[i], existingNode, i);
    }
  }
}

from typing import Callable, List, Optional
import math

class NeuralLayer:
    def __init__(self, inputs: int, outputs: int):
        import random
        scale = math.sqrt(2.0 / inputs)
        self.weights = [[random.gauss(0, scale) for _ in range(inputs)] for _ in range(outputs)]
        self.biases = [0.0] * outputs
        self.last_input: List[float] = []
        self.last_output: List[float] = []

    def forward(self, x: List[float], activation: Callable = None) -> List[float]:
        self.last_input = x
        output = []
        for i in range(len(self.biases)):
            z = sum(w * xi for w, xi in zip(self.weights[i], x)) + self.biases[i]
            output.append(activation(z) if activation else z)
        self.last_output = output
        return output

def relu(x: float) -> float:
    return max(0.0, x)

def sigmoid(x: float) -> float:
    return 1.0 / (1.0 + math.exp(-max(-500, min(500, x))))

def mse_loss(predicted: List[float], actual: List[float]) -> float:
    return sum((p - a) ** 2 for p, a in zip(predicted, actual)) / len(predicted)

class SimpleNN:
    def __init__(self, layer_sizes: List[int]):
        self.layers = [
            NeuralLayer(layer_sizes[i], layer_sizes[i+1])
            for i in range(len(layer_sizes) - 1)
        ]

    def predict(self, x: List[float]) -> List[float]:
        for i, layer in enumerate(self.layers):
            act = sigmoid if i == len(self.layers) - 1 else relu
            x = layer.forward(x, activation=act)
        return x

import os
import json
import gzip
from pathlib import Path
from typing import Any, Optional, Iterator
from datetime import datetime, timedelta

class FileCache:
    """Disk-based key-value cache with TTL and compression."""

    def __init__(self, cache_dir: str = '.cache', default_ttl: int = 3600, compress: bool = True):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.default_ttl = default_ttl
        self.compress = compress

    def _key_path(self, key: str) -> Path:
        safe_key = key.replace('/', '_').replace('\\', '_')
        ext = '.json.gz' if self.compress else '.json'
        return self.cache_dir / f'{safe_key}{ext}'

    def set(self, key: str, value: Any, ttl: Optional[int] = None) -> None:
        entry = {
            'value': value,
            'created_at': datetime.utcnow().isoformat(),
            'expires_at': (datetime.utcnow() + timedelta(seconds=ttl or self.default_ttl)).isoformat()
        }
        path = self._key_path(key)
        data = json.dumps(entry).encode()
        if self.compress:
            with gzip.open(path, 'wb') as f:
                f.write(data)
        else:
            path.write_text(json.dumps(entry))

    def get(self, key: str) -> Optional[Any]:
        path = self._key_path(key)
        if not path.exists():
            return None
        try:
            if self.compress:
                with gzip.open(path, 'rb') as f:
                    entry = json.loads(f.read())
            else:
                entry = json.loads(path.read_text())
            if datetime.fromisoformat(entry['expires_at']) < datetime.utcnow():
                path.unlink()
                return None
            return entry['value']
        except (json.JSONDecodeError, KeyError):
            path.unlink(missing_ok=True)
            return None

    def delete(self, key: str) -> bool:
        path = self._key_path(key)
        if path.exists():
            path.unlink()
            return True
        return False

    def clear(self) -> int:
        count = 0
        for path in self.cache_dir.iterdir():
            if path.suffix in ('.json', '.gz'):
                path.unlink()
                count += 1
        return count

    def keys(self) -> Iterator[str]:
        for path in self.cache_dir.iterdir():
            yield path.stem.replace('.json', '')

class StateMachine {
  constructor(config) {
    this.states = config.states;
    this.currentState = config.initial;
    this.context = config.context || {};
    this.listeners = new Map();
  }

  transition(event) {
    const stateConfig = this.states[this.currentState];
    if (!stateConfig || !stateConfig.on || !stateConfig.on[event]) {
      console.warn(`No transition for event '${event}' in state '${this.currentState}'`);
      return this;
    }

    const transition = stateConfig.on[event];
    const target = typeof transition === 'string' ? transition : transition.target;
    const action = typeof transition === 'object' ? transition.action : null;
    const guard = typeof transition === 'object' ? transition.guard : null;

    if (guard && !guard(this.context)) {
      return this;
    }

    const prevState = this.currentState;

    // Exit actions
    if (stateConfig.onExit) stateConfig.onExit(this.context);

    // Transition action
    if (action) action(this.context);

    this.currentState = target;

    // Entry actions
    const newStateConfig = this.states[this.currentState];
    if (newStateConfig && newStateConfig.onEntry) newStateConfig.onEntry(this.context);

    this._emit('transition', { from: prevState, to: this.currentState, event });
    return this;
  }

  on(eventName, callback) {
    if (!this.listeners.has(eventName)) this.listeners.set(eventName, []);
    this.listeners.get(eventName).push(callback);
    return this;
  }

  _emit(eventName, data) {
    (this.listeners.get(eventName) || []).forEach(cb => cb(data));
  }

  get state() { return this.currentState; }
  matches(state) { return this.currentState === state; }
}
